import { useState } from "react";
import { useNavigate } from "react-router-dom";
import { MapPin, Car, Bike, Bus } from "lucide-react";
import PlannerShell from "../components/PlannerShell";
import ProgressBar from "../components/ProgressBar";
import { StepLayout } from "../components/ui/StepLayout";
import { StepHero } from "../components/ui/StepHero";
import { OptionCard } from "../components/ui/OptionCard";
import { STEP_IMAGES } from "../components/ui/stepImages";

const opts = [
  { icon: "🚶", bg: true, name: "Walking + auto", chip: "Recommended", sub: "Best for most Manali sightseeing spots", price: "₹200/day", CardIcon: MapPin },
  { icon: "🚕", bg: false, name: "Cab (Ola / Uber)", sub: "Comfortable, on-demand", price: "₹600/day", CardIcon: Car },
  { icon: "🛵", bg: false, name: "Bike rental", sub: "Explore at your own pace", price: "₹450/day", CardIcon: Bike },
  { icon: "🚌", bg: false, name: "Public transport", sub: "HRTC buses, shared cabs", price: "₹80/day", CardIcon: Bus },
];

const Local = () => {
  const [selected, setSelected] = useState(0);
  const navigate = useNavigate();
  return (
    <PlannerShell
      mobileHeaderLeft={<span className="back-link" onClick={() => navigate("/food")}>← Back</span>}
      mobileHeaderRight={<span className="header-action" onClick={() => navigate("/plan")}>Skip all</span>}
      footer={(
        <div className="sticky-bottom md:flex md:flex-col md:items-center md:gap-4 md:pt-2">
          <div className="flex w-full max-w-md flex-col items-stretch gap-3 md:mt-6 md:flex-row md:justify-center">
            <button
              type="button"
              className="cta-btn h-11 rounded-lg bg-blue-600 px-5 font-medium text-white transition-all hover:bg-blue-700 active:scale-[0.99] md:max-w-xs md:flex-1"
              onClick={() => navigate("/loading")}
            >
              Build my plan →
            </button>
          </div>
          <div className="skip-link text-center" onClick={() => navigate("/plan")}>Skip this step</div>
        </div>
      )}
    >
      <StepLayout className="planner-container--local planner-stack">
        <ProgressBar activeStep={3} />

        <StepHero
          stepLabel="Step 5 of 5"
          title="Local travel"
          subtitle="How will you get around in Manali?"
          imageSrc={STEP_IMAGES.local}
          imageAlt="Map and travel"
        />

        <div className="planner-local-options md:hidden">
          <div className="planner-section-label">Choose your mode</div>
          {opts.map((o, i) => (
            <div
              key={i}
              className={`planner-opt-with-badge d-opt-card${selected === i ? " d-opt-card--selected" : ""}${i === 0 ? " d-opt-card--rec" : ""}`}
              onClick={() => setSelected(i)}
            >
              {i === 0 && <span className="planner-corner-badge">Recommended</span>}
              <div className={`travel-opt-icon${o.bg ? " blue-bg" : ""}`} style={{ fontSize: 16 }}>{o.icon}</div>
              <div className="travel-opt-info">
                <div className="travel-opt-name">
                  {o.name}
                  {o.chip && <span className="rec-chip">{o.chip}</span>}
                </div>
                <div className="travel-opt-sub">{o.sub}</div>
              </div>
              <div className="d-opt-price-col">
                <div className="travel-opt-price">{o.price}</div>
              </div>
              <div className={`radio-circle${selected === i ? " on" : ""}`} />
            </div>
          ))}
        </div>

        <div className="mt-6 hidden flex-col gap-4 md:flex">
          <div className="text-xs font-medium uppercase tracking-wide text-gray-500">Choose your mode</div>
          <OptionCard
            Icon={opts[0].CardIcon}
            title={opts[0].name}
            chip={opts[0].chip}
            description={opts[0].sub}
            pricePrimary={opts[0].price}
            recommended
            selected={selected === 0}
            onClick={() => setSelected(0)}
          />
          <div className="mt-2 flex flex-col gap-3">
            {opts.slice(1).map((o, i) => (
              <OptionCard
                key={o.name}
                Icon={o.CardIcon}
                title={o.name}
                description={o.sub}
                pricePrimary={o.price}
                selected={selected === i + 1}
                onClick={() => setSelected(i + 1)}
              />
            ))}
          </div>
        </div>
      </StepLayout>
    </PlannerShell>
  );
};

export default Local;
